import{_ as a,c as t,a1 as s,o as r}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Dumping and Cracking SAM hashes to Extract Plaintext passwords","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/2-SAM-Hashes.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/2-SAM-Hashes.md"}'),o={name:"categories/ethical-hacking-labs/5-system-hacking/2-SAM-Hashes.md"};function i(n,e,c,h,l,p){return r(),t("div",null,e[0]||(e[0]=[s('<h1 id="dumping-and-cracking-sam-hashes-to-extract-plaintext-passwords" tabindex="-1">Dumping and Cracking SAM hashes to Extract Plaintext passwords <a class="header-anchor" href="#dumping-and-cracking-sam-hashes-to-extract-plaintext-passwords" aria-label="Permalink to &quot;Dumping and Cracking SAM hashes to Extract Plaintext passwords&quot;">​</a></h1><p>Pwdump7 can be used to dump protected files. Ophcrack is a free open source (GPL) program that cracks Windows passwords by using LM hashes through rainbow tables.</p><p>SAM (Security Account Manager) is a database file present in Windows machines that stores user accounts and security descriptors for users on a local computer. It stores users passwords in a hashed format (in LM hash and NTLM hash). Because a hash function is one-way, this provides some measure of security for the storage of the passwords.</p><p>You need to have administrator access to dump the contents of the SAM file. Assessment of password strength is a critical milestone during your security assessment engagement. You will start your password assessment with a simple SAM hash dump and running it with a hash decryptor to uncover plaintext passwords.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Use the <strong>pwdump7</strong> tool to extract password hashes.</li><li>Use the Ophcrack tool to crack the passwords and obtain plain text passwords.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Windows 10 machine.</li></ul><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><ul><li><a href="https://ophcrack.sourceforge.io/" target="_blank" rel="noreferrer">Ophcrack</a></li><li><a href="https://www.tarasco.org/security/pwdump_7/index.html" target="_blank" rel="noreferrer">Pwdump7</a></li></ul><h2 id="generate-hashes" tabindex="-1">Generate Hashes <a class="header-anchor" href="#generate-hashes" aria-label="Permalink to &quot;Generate Hashes&quot;">​</a></h2><ol><li><p>Before anything, we need to find the User IDs associated with the usernames for Windows 10.</p></li><li><p>Launch the Command prompt in Administrator mode and type:</p></li></ol><p><code>wmic useraccount get name,sid &gt; c:/users.txt</code></p><p>This command we got the usernames and their respective UserIDs. <strong>Make a note of each UserID for further steps.</strong></p><ol start="3"><li>To gather the Password hashes, go to the <strong>pwdump7</strong> folder and execute the .exe file.</li></ol><p><code>cd C:\\Users\\Dummy\\Desktop\\pwdump7</code></p><p><code>PwDump7.exe</code></p><p>To gather this information on external .txt file, type:</p><p><code>PwDump7.exe &gt; c:\\hashes.txt</code></p><p>Now place the usernames before the respective UserIDs that we have gathered in <strong>step 2</strong> and save the file.</p><h2 id="using-ophcrack-to-crack-the-hashes" tabindex="-1">Using Ophcrack to crack the hashes <a class="header-anchor" href="#using-ophcrack-to-crack-the-hashes" aria-label="Permalink to &quot;Using Ophcrack to crack the hashes&quot;">​</a></h2><ol><li>Launch the Ophcrack application.</li><li>Click on <strong>Load</strong> and select <strong>PWDUMP file</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/51d83f1edc90c3f3de3890d72f3a27552a2646b1/ophcrack.png" alt="Ophcrack" title="Ophcrack"></p><ol start="3"><li><p>Next, you will need to <a href="https://ophcrack.sourceforge.io/tables.php" target="_blank" rel="noreferrer">download</a> tables to perform the cracking. Select the <strong>Vista free</strong> to download.</p></li><li><p>Go to the Ophcrack and click the <strong>Tables</strong> menu to load the Table.</p></li><li><p>On the Table Selection window, select the <strong>Vista free</strong>, and click <strong>Ok</strong>.</p></li></ol><p>This table_vista_free is a pre-computed table for reversing cryptographic hash functions and recovering plaintext passwords up to a certain length. The selected <strong>table_vista_free</strong> is installed under the name <strong>Vista free</strong>, which is represented by a <strong>green</strong> colored bullet.</p><ol start="6"><li>Click <strong>Crack</strong> on the menu bar. Ophcrack begins to crack passwords. This action will take a few minutes.</li></ol>',26)]))}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
